const body = $input.first().json.body || $input.first().json;
const kbId = body.kbId;
const sourceUrl = body.sourceUrl;
const sourceBranch = body.sourceBranch || 'main';
const sourcePath = body.sourcePath || '';
const difyDatasetId = body.difyDatasetId;
const difyApiUrl = body.difyApiUrl || 'http://dify-api:5001';
const difyApiKey = body.difyApiKey || '';
const syncJobId = body.syncJobId;
const progressCallbackUrl = body.progressCallbackUrl;
const progressCallbackToken = body.progressCallbackToken || '';
const sourceToken = body.sourceToken || '';

if (!kbId || !sourceUrl || !difyDatasetId || !syncJobId || !difyApiKey) {
  throw new Error('Missing required sync parameters');
}

const match = sourceUrl.match(/github\.com\/([^/]+)\/([^/]+)/);
if (!match) throw new Error('Invalid GitHub URL: ' + sourceUrl);
const owner = match[1];
const repo = match[2].replace(/\.git$/, '');

return [{ json: {
  kbId, owner, repo,
  branch: sourceBranch,
  path: sourcePath,
  difyDatasetId, difyApiUrl, difyApiKey,
  syncJobId, progressCallbackUrl, progressCallbackToken, sourceToken,
  syncStartedAt: new Date().toISOString()
} }];

const items = $input.all();
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        filesProcessed: 0,
        filesTotal: 0,
        step: {
          task: 'Fetch File Tree',
          stepName: 'fetch_file_tree',
          status: 'running',
          startedAt: params.syncStartedAt,
        },
        logMessage:           'Sync started for KB ' + params.kbId,
      },
      json: true,
    });
  } catch {}
}
return items;

const input = $input.first();
const params = $('Parse Sync Params').first().json;

// When continueOnFail=true, failed HTTP nodes put the error on json
const statusCode = input.json.statusCode || 0;
const hasError = !!input.json.error || statusCode >= 400;

if (hasError) {
  const rawMsg = input.json.message || input.json.error || 'Failed to fetch repository file tree';
  const displayMsg = statusCode ? 'HTTP ' + statusCode + ': ' + rawMsg : rawMsg;

  if (params.progressCallbackUrl) {
    const headers = { 'Content-Type': 'application/json' };
    if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: params.progressCallbackUrl,
        headers,
        body: {
          syncJobId: params.syncJobId,
          status: 'failed',
          errorMessage: displayMsg,
          step: {
            task: 'Fetch File Tree',
            stepName: 'fetch_file_tree',
            status: 'failed',
            completedAt: new Date().toISOString(),
            errorMessage: displayMsg,
          },
          logMessage: 'Fetch File Tree failed: ' + displayMsg,
          logSeverity: 'ERROR',
        },
        json: true,
      });
    } catch {}
  }
  throw new Error('Fetch File Tree failed: ' + displayMsg);
}

return [$input.first()];

const response = $input.first().json;
const params = $('Parse Sync Params').first().json;
const skippedFiles = response.skippedFiles || [];

if (skippedFiles.length > 0 && params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;

  const byExt = {};
  for (const f of skippedFiles) {
    const ext = f.ext || 'unknown';
    byExt[ext] = (byExt[ext] || 0) + 1;
  }
  const extSummary = Object.entries(byExt)
    .map(([ext, cnt]) => `.${ext} (${cnt})`)
    .join(', ');

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        step: {
          task: 'Filter Files',
          stepName: 'filter_extensions',
          status: 'completed',
          completedAt: new Date().toISOString(),
          message: `Skipped ${skippedFiles.length} file(s) — unsupported format: ${extSummary}`,
        },
        logMessage: `Skipped ${skippedFiles.length} unsupported file(s): ${extSummary}`,
        logSeverity: 'INFO',
      },
      json: true,
    });
  } catch {}
}

return $input.all();

const response = $input.first().json || {};
const params = $('Parse Sync Params').first().json;

// Handle if the sync-diff node returned an error directly
if (response.error || response.message) {
  if (params.progressCallbackUrl) {
    const headers = { 'Content-Type': 'application/json' };
    if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
    this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'failed',
        errorMessage: String(response.error || response.message || 'Error communicating with gateway'),
        logSeverity: 'ERROR',
      },
      json: true,
    }).catch(() => {});
  }
  throw new Error(String(response.error || response.message || 'Error communicating with gateway'));
}

const files = response.files || [];

if (files.length === 0) {
  if (params.progressCallbackUrl) {
    const headers = { 'Content-Type': 'application/json' };
    if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
    // First mark Fetch File Tree as completed so it doesn't stay 'running'
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        filesProcessed: 0,
        filesTotal: 0,
        step: {
          task: 'Fetch File Tree',
          stepName: 'fetch_file_tree',
          status: 'completed',
          completedAt: new Date().toISOString(),
          message: 'No files to update',
        },
      },
      json: true,
    }).catch(() => {});
    // Then report the skip-sync completion
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'completed',
        filesProcessed: 0,
        filesTotal: 0,
        step: {
          task: 'Skip Sync',
          stepName: 'skip_sync',
          status: 'completed',
          completedAt: new Date().toISOString(),
          message: 'No files needed updating or creating',
        },
        logMessage: 'Sync complete: No files modified since last sync',
        logSeverity: 'INFO',
      },
      json: true,
    }).catch(() => {});
  }
  return [];
}

return files.map((item, index) => ({
  json: {
    ...params,
    filePath: item.path,
    fileSha: item.sha,
    fileExt: (item.path.split('.').pop() || '').toLowerCase(),
    fileIndex: index + 1,
    totalFiles: files.length,
    difyDocumentId: item.difyDocumentId || null,
    isUpdate: !!item.isUpdate
  }
}));

