const items = $input.all();
const summary = $input.first().json;
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl && summary.batchIds.length > 0) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: 'running',
        step: {
          task: 'Dify Indexing',
          stepName: 'dify_indexing',
          status: 'running',
          startedAt: new Date().toISOString(),
          message: 'Indexing ' + summary.batchIds.length + ' files',
        },
        logMessage: 'Indexing ' + summary.batchIds.length + ' files in Dify...',
      },
      json: true,
    });
  } catch {}
}
return items;

const { docIds, batchIds, documentRefs, params, uploadErrors, totalFiles, uploadedCount } = $input.first().json;
const refsByBatch = Object.fromEntries((documentRefs || []).map(ref => [ref.batchId, ref]));
const retryableError = (error) => {
  const normalized = String(error || '').toLowerCase();
  return ['too many requests', 'rate limit', 'ratelimit', '429', 'timeout', 'timed out', 'temporary', 'temporarily', 'embedding', 'upstream', 'unavailable', 'overloaded', 'try again'].some(token => normalized.includes(token));
};
if (!batchIds.length) {
  return [{ json: {
    docIds: [],
    batchIds: [],
    documentRefs: [],
    results: {},
    failedDocuments: [],
    completedCount: 0,
    errorCount: 0,
    timedOut: false,
    uploadErrors: uploadErrors || [],
    finalStatus: uploadErrors && uploadErrors.length ? 'failed' : 'completed',
    params,
    totalFiles,
    uploadedCount,
  } }];
}
const maxAttempts = 24;
const intervalMs = 5000;
const results = {};
const failedByDocId = {};
for (let attempt = 0; attempt < maxAttempts; attempt++) {
  await new Promise(r => setTimeout(r, intervalMs));
  let allDone = true;
  for (const batchId of batchIds) {
    if (results[batchId] === 'completed' || results[batchId] === 'error') continue;
    const ref = refsByBatch[batchId] || {};
    try {
      const data = await this.helpers.httpRequest({
        method: 'GET',
        url: params.difyApiUrl + '/v1/datasets/' + params.difyDatasetId + '/documents/' + batchId + '/indexing-status',
        headers: { Authorization: 'Bearer ' + params.difyApiKey },
        json: true,
      });
      const rows = Array.isArray(data.data) ? data.data : [];
      const statuses = rows.map(item => item.indexing_status).filter(Boolean);
      const erroredRows = rows.filter(item => item.indexing_status === 'error');
      for (const row of erroredRows) {
        const difyDocId = row.id || row.document_id || row.doc_id || ref.difyDocId;
        const error = row.error || row.error_message || row.message || 'Dify indexing failed';
        failedByDocId[difyDocId || batchId] = {
          filePath: ref.filePath || row.name,
          difyDocId,
          batchId,
          indexingStatus: 'error',
          error,
          retryable: retryableError(error),
        };
      }
      const hasError = erroredRows.length > 0 || statuses.includes('error');
      const hasPending = statuses.some(status => !['completed', 'error'].includes(status));
      const status = hasError ? 'error' : (hasPending ? 'indexing' : (statuses.length ? 'completed' : undefined));
      if (status) results[batchId] = status;
      if (status !== 'completed' && status !== 'error') allDone = false;
    } catch (e) {
      allDone = false;
    }
  }
  if (allDone) break;
}
const timedOutBatches = batchIds.filter(batchId => !['completed', 'error'].includes(results[batchId]));
for (const batchId of timedOutBatches) {
  const ref = refsByBatch[batchId] || {};
  failedByDocId[ref.difyDocId || batchId] = {
    filePath: ref.filePath,
    difyDocId: ref.difyDocId,
    batchId,
    indexingStatus: results[batchId] || 'timeout',
    error: 'Indexing timed out',
    retryable: true,
  };
}
const failedDocuments = Object.values(failedByDocId);
const completedCount = Object.values(results).filter(s => s === 'completed').length;
const errorCount = failedDocuments.length;
const timedOut = timedOutBatches.length > 0;
const hasFailures = errorCount > 0 || timedOut || (uploadErrors && uploadErrors.length > 0);
return [{ json: {
  docIds, batchIds, documentRefs, results, failedDocuments, completedCount, errorCount, timedOut,
  uploadErrors: uploadErrors || [],
  finalStatus: hasFailures ? 'failed' : 'completed',
  params,
  totalFiles,
  uploadedCount,
} }];

const items = $input.all();
const summary = $input.first().json;
const params = $('Parse Sync Params').first().json;
const firstUploadError = summary.uploadErrors && summary.uploadErrors.length ? (summary.uploadErrors[0].filePath + ': ' + summary.uploadErrors[0].error) : '';
const failedDocuments = summary.failedDocuments || [];
const firstFailedDoc = failedDocuments.length ? failedDocuments[0] : null;
const failedDocSummary = firstFailedDoc ? ((firstFailedDoc.filePath || firstFailedDoc.difyDocId || 'unknown document') + (firstFailedDoc.error ? ': ' + firstFailedDoc.error : '')) : '';
const finalError = firstUploadError || (failedDocuments.length > 0 ? (failedDocuments.length + ' docs failed indexing: ' + failedDocSummary) : (summary.timedOut ? 'Indexing timed out' : ''));

if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    // If upload errors exist AND indexing was started for some files, finalize dify_indexing first
    // so it doesn't stay stuck in "running". Send as status=running so job isn't closed yet.
    if (summary.uploadErrors && summary.uploadErrors.length > 0 && summary.uploadedCount > 0) {
      await this.helpers.httpRequest({
        method: 'POST',
        url: params.progressCallbackUrl,
        headers,
        body: {
          syncJobId: params.syncJobId,
          status: 'running',
          step: {
            task: 'Dify Indexing',
            stepName: 'dify_indexing',
            status: summary.completedCount > 0 ? 'completed' : 'failed',
            completedAt: new Date().toISOString(),
            message: summary.completedCount + '/' + summary.uploadedCount + ' files indexed',
            errorMessage: failedDocuments.length > 0 ? failedDocSummary : undefined,
            failedDocuments: failedDocuments.length > 0 ? failedDocuments : undefined,
          },
        },
        json: true,
      });
    }
    // Send final job status
    await this.helpers.httpRequest({
      method: 'POST',
      url: params.progressCallbackUrl,
      headers,
      body: {
        syncJobId: params.syncJobId,
        status: summary.finalStatus,
        filesProcessed: summary.totalFiles,
        filesTotal: summary.totalFiles,
        chunksProcessed: summary.completedCount,
        errorMessage: finalError || undefined,
        step: summary.uploadErrors && summary.uploadErrors.length ? {
          task: 'Upload Files',
          stepName: 'upload_files',
          status: 'failed',
          completedAt: new Date().toISOString(),
          message: 'Upload failed for ' + summary.uploadErrors.length + ' file(s)',
          errorMessage: firstUploadError,
        } : {
          task: 'Dify Indexing',
          stepName: 'dify_indexing',
          status: summary.finalStatus,
          completedAt: new Date().toISOString(),
          message: summary.finalStatus === 'completed'
            ? summary.totalFiles + ' / ' + summary.totalFiles + ' indexed'
            : summary.completedCount + ' indexed, ' + failedDocuments.length + ' errors',
          errorMessage: finalError || undefined,
          failedDocuments,
        },
        logMessage: finalError ? ('Sync failed: ' + finalError) : ('Sync complete: ' + summary.completedCount + '/' + summary.totalFiles + ' docs indexed'),
        logSeverity: summary.finalStatus === 'failed' ? 'ERROR' : 'INFO',
      },
      json: true,
    });
  } catch {}
}
return items;
